fn update_events_clickable<C: Callbacks>(events: &[InputEvent], state: &mut C) {
    for ev in events {
        if let InputEvent::Press { x, y } = ev {
            let new_focus =
                if *x >= 104 && *x < 296 && *y >= 94 && *y < 146 { Some(0) }
                else if *x >= 504 && *x < 696 && *y >= 94 && *y < 146 { Some(1) }
                else if *x < 800 && *y >= 150 && *y < 260 { Some(2) }
                else if *x < 800 && *y >= 260 && *y < 370 { Some(3) }
                else if *x < 800 && *y >= 370 && *y < 480 { Some(4) }
                else { None };
            *FOCUSED.lock().unwrap() = new_focus;
            if *x >= 104 && *x < 296 && *y >= 94 && *y < 146 {
                state.nav(&["Borders"]);
            }
            if *x >= 504 && *x < 696 && *y >= 94 && *y < 146 {
                state.nav(&["Focusable"]);
            }
            if *x < 800 && *y >= 150 && *y < 260 {
                state.click();
            }
            if *x < 800 && *y >= 260 && *y < 370 {
                state.action(&["hello"]);
            }
            if *x < 800 && *y >= 370 && *y < 480 {
                state.action(&["a", "b"]);
            }
        }
    }
}

