fn update_changes_progress(backend: &mut dyn Backend, changes: &[(&str, &str)]) {
    if changes.iter().any(|&(n, _)| n == "parameter One") {
        backend.render(&mut |fb, stride| {
            for &(name, val) in changes {
                if name == "parameter One" {
                    atlas_3().blit(fb, stride, 401, 409,
                        &format!("{:<23}", val));
                }
            }
        });
    }
    for &(name, val) in changes {
        if name == "parameter One" {
            if let Ok(v) = val.parse::<f32>() {
                let v = v.clamp(0.0, 1.0);
                let filled = (798.0_f32 * v) as usize;
                let prev = PROG_1_PREV.swap(filled, Ordering::Relaxed);
                if filled != prev {
                    if prev == usize::MAX {
                        if filled > 0 { backend.fill_rect(1, 151, filled, 108, rgb!(255, 255, 255)); }
                        if filled < 798 { backend.fill_rect(1 + filled, 151, 798 - filled, 108, rgb!(0, 0, 0)); }
                    } else if filled > prev {
                        backend.fill_rect(1 + prev, 151, filled - prev, 108, rgb!(255, 255, 255));
                    } else {
                        backend.fill_rect(1 + filled, 151, prev - filled, 108, rgb!(0, 0, 0));
                    }
                }
            }
        }
        if name == "parameter One" {
            if let Ok(v) = val.parse::<f32>() {
                let v = v.clamp(0.0, 1.0);
                let filled = (782.0_f32 * v) as usize;
                let prev = PROG_2_PREV.swap(filled, Ordering::Relaxed);
                if filled != prev {
                    if prev == usize::MAX {
                        if filled > 0 { backend.fill_rect(9, 269, filled, 92, rgb!(0, 255, 0)); }
                        if filled < 782 { backend.fill_rect(9 + filled, 269, 782 - filled, 92, rgb!(40, 40, 40)); }
                    } else if filled > prev {
                        backend.fill_rect(9 + prev, 269, filled - prev, 92, rgb!(0, 255, 0));
                    } else {
                        backend.fill_rect(9 + filled, 269, prev - filled, 92, rgb!(40, 40, 40));
                    }
                }
            }
        }
        if name == "parameter One" {
            if let Ok(v) = val.parse::<f32>() {
                let v = v.clamp(0.0, 1.0);
                let filled = (382.0_f32 * v) as usize;
                let prev = PROG_3_PREV.swap(filled, Ordering::Relaxed);
                if filled != prev {
                    if prev == usize::MAX {
                        if filled > 0 { backend.fill_rect(9, 379, filled, 92, rgb!(0, 255, 0)); }
                        if filled < 382 { backend.fill_rect(9 + filled, 379, 382 - filled, 92, rgb!(40, 40, 40)); }
                    } else if filled > prev {
                        backend.fill_rect(9 + prev, 379, filled - prev, 92, rgb!(0, 255, 0));
                    } else {
                        backend.fill_rect(9 + filled, 379, prev - filled, 92, rgb!(40, 40, 40));
                    }
                }
            }
        }
    }
    {
        let focused = *FOCUSED.lock().unwrap();
        let mut last = LAST_DRAWN_FOCUS.lock().unwrap();
        if *last != focused {
            *last = focused;
            drop(last);
            draw_focus_progress(backend, focused);
        }
    }
}

